（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "87321c4b845b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "411", "s": "0420", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "證券交易法與商業會計法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00080', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-113-3f63b028', 'sub-investigation-d4d4f144-04', NULL, 'essay', 'A商業之商業負責人甲因違反商業會計法「以明知為不實之事項，而填
